body.script:
var notifyEnabled = false;
function requestNotify() {
    if (!('Notification' in window)) return;
    Notification.requestPermission().then(function(perm) {
        if (perm === 'granted') {
            notifyEnabled = true;
            var btn = document.getElementById('notifyBtn');
            btn.textContent = '🔔 ' + (cfg.lang && cfg.lang.notify_on || 'Notifications enabled');
            btn.disabled = true;
        }
    });
}
var cfg, trackingId, stateLabels;
var lastNotifiedState = null;
(function() {
    var raw = document.getElementById('trackingData').getAttribute('data-tracking');
    cfg = JSON.parse(raw);
    trackingId = cfg.tracking_id;
    var lat = cfg.driver_lat || cfg.delivery_lat || 18.4655;
    var lng = cfg.driver_lng || cfg.delivery_lng || -66.1057;
    var stateOrder = ['pending','assigned','in_transit','delivered'];
    var L = cfg.lang || {};
    stateLabels = {
        'pending': L.pending || 'Pending',
        'assigned': L.assigned || 'Driver Assigned',
        'in_transit': L.in_transit || 'In Transit',
        'delivered': L.delivered || 'Delivered',
        'cancelled': L.cancelled || 'Cancelled',
        'failed': L.failed || 'Failed'
    };

    var map = window.L.map('map').setView([lat, lng], 15);
    window.L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '© OpenStreetMap'
    }).addTo(map);
    var marker = window.L.marker([lat, lng]).addTo(map);

    function updateTimeline(st) {
        var idx = stateOrder.indexOf(st);
        var dots = document.querySelectorAll('.tl-dot');
        var labels = document.querySelectorAll('.tl-label');
        dots.forEach(function(d, i) {
            d.className = 'tl-dot' + (i < idx ? ' done' : (i === idx ? ' current' : ''));
            d.textContent = i < idx ? '✓' : '';
        });
        labels.forEach(function(l, i) {
            l.className = 'tl-label' + (i < idx ? ' done' : (i === idx ? ' active' : ''));
        });
    }

    function poll() {
        fetch('/uva/track/' + trackingId + '/status')
            .then(function(r) { return r.json(); })
            .then(function(d) {
                if (d.driver_lat && d.driver_lng) {
                    marker.setLatLng([d.driver_lat, d.driver_lng]);
                    map.panTo([d.driver_lat, d.driver_lng]);
                }
                document.getElementById('etaValue').textContent = d.eta_minutes ? d.eta_minutes + ' min' : '--';
                document.getElementById('statusVal').textContent = stateLabels[d.state] || d.state;
                document.getElementById('updatedVal').textContent = d.updated_at || '';
                updateTimeline(d.state);
                if (notifyEnabled && d.state !== lastNotifiedState) {
                    lastNotifiedState = d.state;
                    if (d.state === 'in_transit') {
                        new Notification('🛵 ' + (stateLabels.in_transit || 'On the way!'), {
                            body: d.eta_minutes ? 'ETA: ' + d.eta_minutes + ' min' : '',
                            icon: '/odoo_uva_connector/static/description/icon.png'
                        });
                    } else if (d.state === 'delivered') {
                        new Notification('✅ ' + (stateLabels.delivered || 'Delivered!'), {
                            body: cfg.lang && cfg.lang.final || 'Your order has arrived.',
                            icon: '/odoo_uva_connector/static/description/icon.png'
                        });
                    }
                }
                if (d.state === 'delivered' || d.state === 'cancelled' || d.state === 'failed') {
                    document.getElementById('etaSub').textContent = cfg.lang && cfg.lang.final || 'Final status';
                    clearInterval(pollInterval);
                }
            })
            .catch(function() {});
    }

    var pollInterval = setInterval(poll, 15000);
})();
